      <rect x="522" y="44" width="168" height="38" rx="6" fill="rgba(52,211,153,.2)" stroke="#34d399"/>
      <text x="606" y="68" fill="#34d399" font-size="13" font-weight="700" text-anchor="middle">Safe harbor</text>

      <text x="15" y="116" fill="#a1a1aa" font-size="13">Raise cap</text>
